import re

def parse_log(log):
    log = log.split(" ")
    template = ""
    for i in log:
        if re.match(r'\d+', i) or re.match(r'[a-z]+', i) or re.match(r'\w+\-\w+', i):
            template += " <*> "
        else:
            template += " " + i + " "
    return template.strip()

